# ========== INICIALIZADOR DE MELHORIAS - JARVIS-IA ==========\n# Arquivo: init_melhorias.R\n# DescriГ§ГЈo: Script Гєnico para carregar todas as melhorias\n# Uso: source(\"init_melhorias.R\")\n# ===========================================================\n\ncat(\"\\n\")\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\")\ncat(\"          рџљЂ INICIALIZADOR DE MELHORIAS - JARVIS-IA v2.0\\n\")\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\\n\")\n\n# Verificar diretГіrio de trabalho\nif (!file.exists(\"CLASSIFICADOR_VERSAO14.2.R\")) {\n  cat(\"вќЊ ERRO: CLASSIFICADOR_VERSAO14.2.R nГЈo encontrado\\n\")\n  cat(\"в„№пёЏ  Certifique-se de estar no diretГіrio correto\\n\\n\")\n  stop(\"Arquivo V14.2 nГЈo encontrado\")\n}\n\n# ================================================================\n# 1. CARREGAR MГ“DULOS DE MELHORIA\n# ================================================================\n\ncat(\"рџ“¦ Carregando mГіdulos de melhoria...\\n\\n\")\n\n# Flag para rastrear carregamentos\nmodulos_carregados <- list(\n  logger = FALSE,\n  backup = FALSE,\n  paralelo = FALSE,\n  api = FALSE\n)\n\n# 1.1 Logger System\ncat(\"  вЏі Logger System... \")\ntryCatch({\n  if (file.exists(\"logger_system.R\")) {\n    source(\"logger_system.R\", encoding = \"UTF-8\")\n    cat(\"вњ…\\n\")\n    modulos_carregados$logger <- TRUE\n  } else {\n    cat(\"вљ пёЏ  (arquivo nГЈo encontrado)\\n\")\n  }\n}, error = function(e) {\n  cat(\"вќЊ Erro: \", e$message, \"\\n\")\n})\n\n# 1.2 Backup System\ncat(\"  вЏі Backup System... \")\ntryCatch({\n  if (file.exists(\"backup_system.R\")) {\n    source(\"backup_system.R\", encoding = \"UTF-8\")\n    cat(\"вњ…\\n\")\n    modulos_carregados$backup <- TRUE\n  } else {\n    cat(\"вљ пёЏ  (arquivo nГЈo encontrado)\\n\")\n  }\n}, error = function(e) {\n  cat(\"вќЊ Erro: \", e$message, \"\\n\")\n})\n\n# 1.3 Processamento Paralelo\ncat(\"  вЏі Processamento Paralelo... \")\ntryCatch({\n  if (file.exists(\"parallel_processing.R\")) {\n    # Verificar se future estГЎ disponГ­vel\n    if (!requireNamespace(\"future\", quietly = TRUE)) {\n      cat(\"вљ пёЏ  (future nГЈo instalado)\\n\")\n    } else {\n      source(\"parallel_processing.R\", encoding = \"UTF-8\")\n      cat(\"вњ…\\n\")\n      modulos_carregados$paralelo <- TRUE\n    }\n  } else {\n    cat(\"вљ пёЏ  (arquivo nГЈo encontrado)\\n\")\n  }\n}, error = function(e) {\n  cat(\"вќЊ Erro: \", e$message, \"\\n\")\n})\n\n# 1.4 API REST\ncat(\"  вЏі API REST (plumber)... \")\ntryCatch({\n  if (file.exists(\"api_rest.R\")) {\n    if (!requireNamespace(\"plumber\", quietly = TRUE)) {\n      cat(\"вљ пёЏ  (plumber nГЈo instalado)\\n\")\n    } else {\n      # NГЈo fazer source direto de api_rest.R aqui\n      # pois precisa de contexto plumber\n      cat(\"вњ… (carregГЎvel)\\n\")\n      modulos_carregados$api <- TRUE\n    }\n  } else {\n    cat(\"вљ пёЏ  (arquivo nГЈo encontrado)\\n\")\n  }\n}, error = function(e) {\n  cat(\"вќЊ Erro: \", e$message, \"\\n\")\n})\n\n# ================================================================\n# 2. DIAGNГ“STICO DO SISTEMA\n# ================================================================\n\ncat(\"\\nрџ“Љ DiagnГіstico do Sistema:\\n\\n\")\n\n# Verificar dependГЄncias crГ­ticas\ndeps_criticas <- c(\"shiny\", \"shinydashboard\", \"DT\", \"dplyr\", \"tidyr\")\ndeps_opcionales <- c(\"future\", \"furrr\", \"plumber\", \"testthat\")\n\ncat(\"  DependГЄncias CrГ­ticas:\\n\")\nfor (pkg in deps_criticas) {\n  status <- ifelse(requireNamespace(pkg, quietly = TRUE), \"вњ…\", \"вќЊ\")\n  cat(\"    \", status, pkg, \"\\n\")\n}\n\ncat(\"\\n  DependГЄncias Opcionais:\\n\")\nfor (pkg in deps_opcionales) {\n  status <- ifelse(requireNamespace(pkg, quietly = TRUE), \"вњ…\", \"вљ пёЏ\")\n  cat(\"    \", status, pkg, \"\\n\")\n}\n\n# ================================================================\n# 3. RESUMO DE CARREGAMENTO\n# ================================================================\n\ncat(\"\\nрџ“‹ Resumo de Carregamento:\\n\\n\")\n\nmodulos_ativos <- sum(unlist(modulos_carregados))\ntotal_modulos <- length(modulos_carregados)\n\ncat(\"  MГіdulos carregados: \", modulos_ativos, \"/\", total_modulos, \"\\n\\n\")\n\nif (modulos_carregados$logger) {\n  cat(\"  вњ… Logger System\n     в””в”Ђ Use: log_info(), log_error(), log_warning(), log_audit()\n     в””в”Ђ Status: \", get_log_summary()$total_errors, \" erros registrados\\n\\n\")\n}\n\nif (modulos_carregados$backup) {\n  backup_status <- get_backup_status()\n  cat(\"  вњ… Backup System\n     в””в”Ђ Agendador: \", ifelse(backup_status$scheduler_active, \"ATIVO\", \"INATIVO\"), \"\n     в””в”Ђ Гљltimos backups: \", backup_status$total_backups, \"\n     в””в”Ђ Tamanho total: \", round(backup_status$total_size_mb, 2), \" MB\\n\\n\")\n}\n\nif (modulos_carregados$paralelo) {\n  cat(\"  вњ… Processamento Paralelo\n     в””в”Ђ Status: \", ifelse(PARALLEL_CONFIG$enabled, \"ATIVO\", \"INATIVO\"), \"\n     в””в”Ђ Workers: \", PARALLEL_CONFIG$workers, \"\n     в””в”Ђ Min registros: \", PARALLEL_CONFIG$min_records_for_parallel, \"\\n\\n\")\n}\n\nif (modulos_carregados$api) {\n  cat(\"  вњ… API REST\n     в””в”Ђ Executar: plumber::plumb_run('api_rest.R', port = 8000)\n     в””в”Ђ Docs: http://localhost:8000/docs\\n\\n\")\n}\n\n# ================================================================\n# 4. MENU DE AГ‡Г•ES RГЃPIDAS\n# ================================================================\n\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\")\ncat(\"рџЋЇ AГ‡Г•ES RГЃPIDAS (copie e execute no console):\\n\")\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\\n\")\n\nif (modulos_carregados$logger) {\n  cat(\"Logger:     log_info('Teste', 'test') | flush_log_buffer()\\n\")\n}\n\nif (modulos_carregados$backup) {\n  cat(\"Backup:     execute_backup() | print_backup_status()\\n\")\n}\n\nif (modulos_carregados$paralelo) {\n  cat(\"Paralelo:   PARALLEL_CONFIG$enabled <- TRUE | print_parallel_config()\\n\")\n}\n\ncat(\"Testes:     testthat::test_file('tests.R')\\n\")\ncat(\"API:        plumber::plumb_run('api_rest.R', port = 8000)\\n\")\n\ncat(\"\\n\")\n\n# ================================================================\n# 5. PRГ“XIMOS PASSOS\n# ================================================================\n\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\")\ncat(\"рџ“љ PRГ“XIMOS PASSOS:\\n\")\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\\n\")\n\ncat(\"1пёЏвѓЈ  Leia: GUIA_INTEGRACAO_MELHORIAS_V14.2.md\\n\")\ncat(\"2пёЏвѓЈ  Execute: testthat::test_file('tests.R')\\n\")\ncat(\"3пёЏвѓЈ  Integre: Siga o guia para adicionar ao V14.2\\n\")\ncat(\"4пёЏвѓЈ  Teste: Verifique dashboard administrativo\\n\")\ncat(\"5пёЏвѓЈ  Deploy: Use backup_system + logger + paralelo\\n\")\n\ncat(\"\\n\")\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\")\ncat(\"вњ… INICIALIZADOR CONCLUГЌDO - Sistema Pronto!\\n\")\ncat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\\n\")\n\n# ================================================================\n# 6. FUNГ‡ГѓO AUXILIAR: INSTALAR DEPENDГЉNCIAS\n# ================================================================\n\ninstalar_dependencias <- function(completo = FALSE) {\n  cat(\"\\nрџ“¦ Instalando dependГЄncias...\\n\\n\")\n  \n  deps_criticas <- c(\n    \"shiny\", \"shinydashboard\", \"shinydashboardPlus\", \n    \"shinyWidgets\", \"shinyjs\", \"DT\", \"dplyr\", \"tidyr\", \n    \"readxl\", \"openxlsx\", \"ggplot2\", \"lubridate\", \"stringr\"\n  )\n  \n  deps_opcionais <- c(\n    \"future\", \"furrr\", \"plumber\", \"testthat\", \n    \"plotly\", \"jsonlite\", \"httr\", \"caret\", \"randomForest\", \"tm\"\n  )\n  \n  if (completo) {\n    packages_to_install <- c(deps_criticas, deps_opcionais)\n  } else {\n    packages_to_install <- deps_criticas\n  }\n  \n  for (pkg in packages_to_install) {\n    if (!requireNamespace(pkg, quietly = TRUE)) {\n      cat(\"  рџ“Ґ Instalando\", pkg, \"... \")\n      tryCatch({\n        install.packages(pkg, quiet = TRUE)\n        cat(\"вњ…\\n\")\n      }, error = function(e) {\n        cat(\"вќЊ Erro\\n\")\n      })\n    }\n  }\n  \n  cat(\"\\nвњ… InstalaГ§ГЈo concluГ­da!\\n\\n\")\n}\n\n# ================================================================\n# 7. EXPORTAR FUNГ‡Г•ES ГљTEIS\n# ================================================================\n\n# FunГ§ГЈo auxiliar para status rГЎpido\nstatus_sistema <- function() {\n  cat(\"\\nрџ“Љ STATUS DO SISTEMA\\n\")\n  cat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\")\n  \n  if (modulos_carregados$logger) {\n    cat(\"Logger: вњ… Ativo\\n\")\n    if (exists(\"get_log_summary\")) {\n      summary <- get_log_summary()\n      cat(\"  в””в”Ђ Erros: \", summary$total_errors, \"\\n\")\n    }\n  } else {\n    cat(\"Logger: вќЊ Inativo\\n\")\n  }\n  \n  if (modulos_carregados$backup) {\n    cat(\"Backup: вњ… Ativo\\n\")\n    if (exists(\"get_backup_status\")) {\n      status <- get_backup_status()\n      cat(\"  в””в”Ђ Scheduler: \", ifelse(status$scheduler_active, \"вњ…\", \"вќЊ\"), \"\\n\")\n    }\n  } else {\n    cat(\"Backup: вќЊ Inativo\\n\")\n  }\n  \n  if (modulos_carregados$paralelo) {\n    cat(\"Paralelo: вњ… Pronto\\n\")\n    cat(\"  в””в”Ђ Status: \", ifelse(PARALLEL_CONFIG$enabled, \"ATIVO\", \"INATIVO\"), \"\\n\")\n  } else {\n    cat(\"Paralelo: вќЊ NГЈo carregado\\n\")\n  }\n  \n  cat(\"в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\\n\\n\")\n}\n\n# Exportar funГ§ГЈo\nif (!exists(\"status_sistema\", inherits = FALSE)) {\n  assign(\"status_sistema\", status_sistema, envir = .GlobalEnv)\n}\n\ncat(\"рџ’Ў Dica: Execute 'status_sistema()' para ver status em tempo real\\n\")\ncat(\"рџ’Ў Dica: Execute 'instalar_dependencias(completo = TRUE)' para todas\\n\\n\")\n"